/**
 * This endpoint creates a missing employment for a PEO contract.
 * Use when a contract exists but employment was not created (e.g., entity transfer bug).
 *
 * The endpoint will:
 * 1. Check if employment already exists (skip if it does)
 * 2. Fetch required data from contract and peo_contracts
 * 3. Lookup jobTitle from jobCode if needed
 * 4. Create employment via Employment microservice
 *
 * Example tickets: ENGESC-23650, ENGESC-23600
 */
@Post('/contract/:oid/create_missing_employment')
@Joi((joi, db) => ({
    params: joi.object().keys({
        oid: joi.publicId(db.Contract).permission('admin:contracts.write', db.Contract).secure().resolve(false).required(),
    }),
    body: joi.object().keys({
        // Optional overrides for backfill scenarios
        startDate: joi.plainDateString().optional(),
        jobTitle: joi.string().min(1).max(255).optional(),
        payrollSettingsId: joi.string().uuid().optional(),
    }),
}))
async createMissingEmployment({params, body, res}) {
    const {oid: contractOid} = params;
    const {startDate: overrideStartDate, jobTitle: overrideJobTitle, payrollSettingsId: overridePayrollSettingsId} = body;

    try {
        const result = await peoContractService.createMissingEmploymentForContract({
            contractOid,
            overrideStartDate,
            overrideJobTitle,
            overridePayrollSettingsId,
        });

        return res.status(HTTP_CODES.ok).json(result);
    } catch (error) {
        if (error instanceof HttpError) {
            throw error;
        }

        return res.status(HTTP_CODES.unprocessable_entity).json({
            success: false,
            error: error.message,
            contractOid,
        });
    }
}
```

